import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { DashboardStats } from '../types';
import api from '../utils/api';
import { useAuth } from '../hooks/useAuth';

function getGreeting() {
  const h = new Date().getHours();
  if (h>=5  && h<12) return 'Good Morning';
  if (h>=12 && h<17) return 'Good Afternoon';
  if (h>=17 && h<21) return 'Good Evening';
  return 'Good Night';
}

export default function Dashboard() {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [stats, setStats] = useState<DashboardStats|null>(null);
  const [loading, setLoading] = useState(true);
  const isStaff = user?.userType === 'user';

  useEffect(() => {
    api.get('/borrows/stats').then(r=>{setStats(r.data.data);setLoading(false);}).catch(()=>setLoading(false));
  }, []);

  if (loading) return (
    <div style={{display:'flex',alignItems:'center',justifyContent:'center',height:'100vh'}}>
      <div style={{width:36,height:36,border:'3px solid transparent',borderTopColor:'#7c5cff',borderRightColor:'#c9a84c',borderRadius:'50%',animation:'spin 1s linear infinite'}}/>
    </div>
  );

  const cards = [
    { label:'Total Books',    value:stats?.totalBooks||0,     accent:'#7c5cff', glow:'rgba(124,92,255,0.25)',    tag:'Library'  },
    { label:'Active Members', value:stats?.totalMembers||0,   accent:'#39ff8f', glow:'rgba(57,255,143,0.2)',     tag:'Enrolled' },
    { label:'Books Out',      value:stats?.activeBorrows||0,  accent:'#c9a84c', glow:'rgba(201,168,76,0.25)',    tag:'Active'   },
    { label:'Overdue',        value:stats?.overdueBorrows||0, accent:'#ff4da6', glow:'rgba(255,77,166,0.2)',     tag:'Urgent'   },
  ];

  const roleDisplay = user?.role==='librarian'?'Head Librarian':user?.role==='library_assistant'?'Asst. Librarian':user?.role==='student'?'Student':'Staff Member';

  return (
    <div className="page-enter" style={{padding:'28px 36px',width:'100%'}}>
      <style>{`
        .scard { transition:all .25s cubic-bezier(.16,1,.3,1) !important; cursor:default !important; }
        .scard:hover { transform:translateY(-5px) !important; }
        .al-btn { transition:all .18s !important; cursor:pointer !important; }
        .al-btn:hover { transform:translateX(4px); }
        .lrow { border-radius:10px; transition:background .15s !important; }
        .lrow:hover { background:rgba(124,92,255,0.06) !important; }
        [data-theme="dark"] .scard:hover { box-shadow:0 20px 50px rgba(0,0,0,0.5), 0 0 0 1px rgba(255,255,255,0.05) !important; }
      `}</style>

      {/* ── Header ── */}
      <div style={{display:'flex',alignItems:'flex-start',justifyContent:'space-between',marginBottom:32,gap:16}}>
        <div>
          <p style={{fontSize:11,color:'var(--text-muted)',letterSpacing:'2.5px',textTransform:'uppercase',marginBottom:10,fontWeight:600,fontFamily:"'Space Mono',monospace"}}>
            {new Date().toLocaleDateString('en-US',{weekday:'long',year:'numeric',month:'long',day:'numeric'})}
          </p>
          <h1 style={{fontFamily:"'Playfair Display',serif",fontSize:36,fontWeight:700,color:'var(--text)',lineHeight:1.1,letterSpacing:'-0.5px'}}>
            {getGreeting()},&nbsp;
            <span style={{color:'#c9a84c'}}>{user?.name?.split(' ')[0]}</span>
          </h1>
          <p style={{fontSize:14,color:'var(--text-dim)',marginTop:8}}>
            Welcome to the BAUST Library Management System
          </p>
        </div>

        {/* Role badge */}
        <div style={{
          background:'var(--gold-dim)', border:'1px solid rgba(201,168,76,0.2)',
          borderRadius:16, padding:'14px 22px',
          display:'flex', flexDirection:'column', alignItems:'center',
          textAlign:'center', flexShrink:0, minWidth:140,
          boxShadow:'0 0 30px var(--gold-glow)'
        }}>
          <div style={{fontSize:10,color:'var(--text-muted)',letterSpacing:'1.5px',textTransform:'uppercase',fontWeight:700,marginBottom:5,fontFamily:"'Space Mono',monospace"}}>Signed in as</div>
          <div style={{fontSize:15,fontWeight:800,color:'#c9a84c'}}>{roleDisplay}</div>
          {user?.member_id && <div style={{fontSize:11,color:'var(--text-dim)',marginTop:4,fontFamily:"'Space Mono',monospace",letterSpacing:'1px'}}>#{user.member_id}</div>}
        </div>
      </div>

      {/* ── Alerts ── */}
      {isStaff && stats && stats.pendingMembers>0 && (
        <div className="al-btn" onClick={()=>navigate('/members?status=pending')}
          style={{background:'rgba(245,158,11,0.06)',border:'1px solid rgba(245,158,11,0.2)',borderRadius:14,padding:'14px 20px',marginBottom:12,display:'flex',alignItems:'center',gap:14,cursor:'pointer'}}>
          <div style={{width:8,height:8,borderRadius:'50%',background:'#fbbf24',boxShadow:'0 0 10px #fbbf24',flexShrink:0,animation:'pulse-glow 2s infinite'}}/>
          <div style={{flex:1}}>
            <div style={{fontSize:14,fontWeight:700,color:'#fbbf24'}}>{stats.pendingMembers} account(s) waiting for approval</div>
            <div style={{fontSize:12,color:'rgba(251,191,36,0.4)',marginTop:2}}>Click to review pending members →</div>
          </div>
        </div>
      )}
      {isStaff && stats && stats.pendingRequests>0 && (
        <div className="al-btn" onClick={()=>navigate('/requests')}
          style={{background:'rgba(124,92,255,0.06)',border:'1px solid rgba(124,92,255,0.2)',borderRadius:14,padding:'14px 20px',marginBottom:24,display:'flex',alignItems:'center',gap:14,cursor:'pointer'}}>
          <div style={{width:8,height:8,borderRadius:'50%',background:'#7c5cff',boxShadow:'0 0 10px #7c5cff',flexShrink:0,animation:'pulse-glow 2s infinite'}}/>
          <div style={{flex:1}}>
            <div style={{fontSize:14,fontWeight:700,color:'#a78bfa'}}>{stats.pendingRequests} borrow request(s) pending</div>
            <div style={{fontSize:12,color:'rgba(167,139,250,0.4)',marginTop:2}}>Click to review and approve →</div>
          </div>
        </div>
      )}

      {stats && (<>
        {/* ── Stat Cards ── */}
        <div style={{display:'grid',gridTemplateColumns:'repeat(4,1fr)',gap:16,marginBottom:24}}>
          {cards.map((c,i)=>(
            <div key={c.label} className="scard"
              style={{background:'var(--bg2)',border:'1px solid var(--border)',borderRadius:20,padding:'22px 20px 20px',position:'relative',overflow:'hidden'}}
            >
              {/* Top accent line */}
              <div style={{position:'absolute',top:0,left:0,right:0,height:2,background:`linear-gradient(90deg,transparent,${c.accent},transparent)`,opacity:.7}}/>
              {/* Ambient glow */}
              <div style={{position:'absolute',top:-20,right:-20,width:100,height:100,background:c.glow,borderRadius:'50%',filter:'blur(30px)',pointerEvents:'none'}}/>

              <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:18}}>
                <span style={{fontSize:11,fontWeight:700,padding:'3px 11px',borderRadius:99,background:c.accent+'18',color:c.accent,letterSpacing:'.5px',border:`1px solid ${c.accent}28`}}>{c.tag}</span>
              </div>
              <div style={{fontFamily:"'Playfair Display',serif",fontSize:46,fontWeight:700,color:'var(--text)',lineHeight:1,marginBottom:6,letterSpacing:'-2px',
                textShadow:`0 0 40px ${c.accent}40`
              }}>{c.value}</div>
              <div style={{fontSize:13,color:'var(--text-dim)',fontWeight:500,marginBottom:14}}>{c.label}</div>
              {/* Progress bar */}
              <div style={{height:2,background:'rgba(255,255,255,0.05)',borderRadius:99,overflow:'hidden'}}>
                <div style={{height:'100%',width:c.value>0?'60%':'5%',background:`linear-gradient(90deg,${c.accent},${c.accent}44)`,borderRadius:99,
                  boxShadow:`0 0 8px ${c.accent}`}}/>
              </div>
            </div>
          ))}
        </div>

        {/* ── Bottom panels ── */}
        <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:18}}>

          {/* Recent Borrows */}
          <div style={{background:'var(--bg2)',border:'1px solid var(--border)',borderRadius:18,padding:'22px 22px',position:'relative',overflow:'hidden'}}>
            <div style={{position:'absolute',top:-30,right:-30,width:120,height:120,background:'rgba(124,92,255,0.05)',borderRadius:'50%',filter:'blur(30px)',pointerEvents:'none'}}/>
            <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:18}}>
              <h3 style={{fontFamily:"'Playfair Display',serif",fontSize:17,fontWeight:700,color:'var(--text)'}}>Recent Borrows</h3>
              <span style={{fontSize:11,color:'var(--text-muted)',background:'var(--bg3)',border:'1px solid var(--border)',padding:'3px 10px',borderRadius:99,fontWeight:600}}>Latest 5</span>
            </div>
            {stats.recentBorrows.length ? stats.recentBorrows.map((b:any)=>(
              <div key={b.id} className="lrow" style={{display:'flex',alignItems:'center',gap:12,padding:'10px 12px',marginBottom:3}}>
                <div className="status-dot" style={{background:b.status==='returned'?'#39ff8f':b.status==='overdue'?'#ff4da6':'#c9a84c',
                  boxShadow:`0 0 8px ${b.status==='returned'?'#39ff8f':b.status==='overdue'?'#ff4da6':'#c9a84c'}`,flexShrink:0}}/>
                <div style={{flex:1,minWidth:0}}>
                  <div style={{fontSize:13,fontWeight:600,color:'var(--text)',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{b.title}</div>
                  <div style={{fontSize:11,color:'var(--text-dim)',marginTop:1}}>{b.member_name}</div>
                </div>
                <span style={{fontSize:11,fontWeight:700,padding:'3px 10px',borderRadius:99,textTransform:'capitalize',flexShrink:0,
                  background:b.status==='returned'?'rgba(57,255,143,0.1)':b.status==='overdue'?'rgba(255,77,166,0.1)':'rgba(201,168,76,0.1)',
                  color:b.status==='returned'?'#39ff8f':b.status==='overdue'?'#ff4da6':'#c9a84c',
                  border:`1px solid ${b.status==='returned'?'rgba(57,255,143,0.2)':b.status==='overdue'?'rgba(255,77,166,0.2)':'rgba(201,168,76,0.2)'}`
                }}>{b.status}</span>
              </div>
            )) : <div style={{textAlign:'center',padding:'28px 0',color:'var(--text-muted)',fontSize:13,fontStyle:'italic'}}>No borrows yet</div>}
          </div>

          {/* Popular Books */}
          <div style={{background:'var(--bg2)',border:'1px solid var(--border)',borderRadius:18,padding:'22px 22px',position:'relative',overflow:'hidden'}}>
            <div style={{position:'absolute',top:-30,right:-30,width:120,height:120,background:'rgba(201,168,76,0.05)',borderRadius:'50%',filter:'blur(30px)',pointerEvents:'none'}}/>
            <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',marginBottom:18}}>
              <h3 style={{fontFamily:"'Playfair Display',serif",fontSize:17,fontWeight:700,color:'var(--text)'}}>Popular Books</h3>
              <span style={{fontSize:11,color:'var(--text-muted)',background:'var(--bg3)',border:'1px solid var(--border)',padding:'3px 10px',borderRadius:99,fontWeight:600}}>Top 5</span>
            </div>
            {stats.popularBooks.length ? stats.popularBooks.map((b:any,i:number)=>(
              <div key={b.title} className="lrow" style={{display:'flex',alignItems:'center',gap:12,padding:'10px 12px',marginBottom:3}}>
                <div style={{width:26,height:26,borderRadius:8,flexShrink:0,display:'flex',alignItems:'center',justifyContent:'center',fontSize:11,fontWeight:800,
                  background:i===0?'linear-gradient(135deg,#c9a84c,#a87d30)':i===1?'rgba(148,163,184,0.1)':i===2?'rgba(180,100,60,0.1)':'rgba(255,255,255,0.04)',
                  color:i===0?'#1a1a2e':i===1?'#94a3b8':i===2?'#b47844':'var(--text-muted)',
                  boxShadow:i===0?'0 0 12px rgba(201,168,76,0.5)':'none'
                }}>{i+1}</div>
                <div style={{flex:1,minWidth:0}}>
                  <div style={{fontSize:13,fontWeight:600,color:'var(--text)',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{b.title}</div>
                  <div style={{fontSize:11,color:'var(--text-dim)',marginTop:1}}>{b.author}</div>
                </div>
                <div style={{fontSize:13,fontWeight:800,color:'#c9a84c',flexShrink:0}}>{b.borrow_count}×</div>
              </div>
            )) : <div style={{textAlign:'center',padding:'28px 0',color:'var(--text-muted)',fontSize:13,fontStyle:'italic'}}>No data yet</div>}
          </div>
        </div>
      </>)}
    </div>
  );
}
